-- ============================================================
-- BlueBush Migration 003: Variant SKU Support
-- Run via: psql $SUPABASE_DB_URL -f migrations/003_variant_skus.sql
-- Idempotent: safe to run multiple times.
-- ============================================================

-- ===== PART 2a: ADD COLUMNS TO PRODUCTS TABLE =====

-- Add parent_id for variant child products
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS parent_id TEXT REFERENCES products(id) ON DELETE CASCADE;

-- Add variant_label for display on the frontend
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS variant_label TEXT;

-- Add per-variant commercial description
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS variant_description TEXT;

-- Add variant_marketing_hook for per-variant marketing copy
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS variant_marketing_hook TEXT;

-- Index for looking up all children of a parent
CREATE INDEX IF NOT EXISTS idx_products_parent_id ON products (parent_id);

-- ===== PART 2b: NOTE ON place_order RPC =====
-- NOTE: The place_order RPC already decrements stock on the specific product_id
-- passed per order item. When the frontend passes a variant SKU ID (e.g. BATH-003-ROSE-GOLD)
-- instead of the parent ID (BATH-003), the stock decrement will correctly target that variant.
-- No changes to place_order are needed.

-- ===== PART 2c: PUBLIC READ POLICY FOR PRODUCTS =====
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE tablename = 'products'
      AND policyname = 'public_read_products'
  ) THEN
    CREATE POLICY "public_read_products"
      ON products FOR SELECT USING (true);
  END IF;
END
$$;

-- ===== PART 2d: get_variant_skus RPC =====
CREATE OR REPLACE FUNCTION get_variant_skus(p_parent_id TEXT)
RETURNS TABLE (
  id          TEXT,
  variant_label TEXT,
  price_aud   NUMERIC,
  stock_level INTEGER,
  status      TEXT,
  variant_description TEXT,
  variant_marketing_hook TEXT
)
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT
    id,
    variant_label,
    price_aud,
    stock_level,
    status,
    variant_description,
    variant_marketing_hook
  FROM products
  WHERE parent_id = p_parent_id
  ORDER BY id;
$$;

GRANT EXECUTE ON FUNCTION get_variant_skus TO anon;

